// Extract and validate configuration from request
const body = $input.item.json.body || $input.item.json;

// Required fields validation
if (!body.recordingUrl) {
  throw new Error('recordingUrl is required');
}

if (!body.meetingSource || !['zoom', 'google_meet', 'teams'].includes(body.meetingSource)) {
  throw new Error('meetingSource must be one of: zoom, google_meet, teams');
}

// Build configuration
const config = {
  meetingSource: body.meetingSource,
  recordingUrl: body.recordingUrl,
  meetingTitle: body.meetingTitle || 'Untitled Meeting',
  meetingDate: body.meetingDate || new Date().toISOString().split('T')[0],
  attendees: body.attendees || [],
  projectKey: body.projectKey || 'GENERAL',
  taskTool: body.taskTool || 'jira', // jira, clickup, linear
  defaultPriority: body.defaultPriority || 'medium',
  autoAssign: Boolean(body.autoAssign !== false),
  sendNotifications: Boolean(body.sendNotifications !== false),
  saveToNotion: Boolean(body.saveToNotion),
  saveToDrive: Boolean(body.saveToDrive !== false),
  extractDecisions: Boolean(body.extractDecisions !== false),
  extractRisks: Boolean(body.extractRisks !== false),
  dueDate: body.dueDate || null,
  transcriptionLanguage: body.transcriptionLanguage || 'en'
};

// Team member mapping (email to user IDs in different platforms)
const teamMapping = body.teamMapping || {
  // Example structure - should be customized per organization
  'user@example.com': {
    name: 'Alice Johnson',
    jiraAccountId: 'account-id-1',
    clickupUserId: '12345',
    linearUserId: 'linear-user-1',
    slackUserId: 'U01ABC123'
  },
  'user@example.com': {
    name: 'Bob Smith',
    jiraAccountId: 'account-id-2',
    clickupUserId: '67890',
    linearUserId: 'linear-user-2',
    slackUserId: 'U02DEF456'
  }
};

// Metadata
const metadata = {
  workflowId: `MNA-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
  startedAt: new Date().toISOString(),
  timezone: body.timezone || 'UTC'
};

return {
  json: {
    config,
    teamMapping,
    metadata,
    rawBody: body
  }
};

// Check if file is video (needs audio extraction) or already audio
const binaryData = Object.values($input.item.binary)[0];
const fileName = binaryData.fileName || '';
const mimeType = binaryData.mimeType || '';

const isVideo = mimeType.includes('video') || fileName.match(/\.(mp4|mov|avi|mkv)$/i);
const isAudio = mimeType.includes('audio') || fileName.match(/\.(mp3|wav|m4a|ogg)$/i);

return {
  json: {
    fileName,
    mimeType,
    isVideo,
    isAudio,
    needsConversion: isVideo,
    binaryKey: Object.keys($input.item.binary)[0],
    config: $('Validate Config & Build Params').item.json.config,
    metadata: $('Validate Config & Build Params').item.json.metadata
  },
  binary: $input.item.binary
};

// Parse and clean transcription result
const transcription = $input.item.json;
let transcriptText = transcription.text || transcription.transcription || '';

// Clean up common transcription artifacts
transcriptText = transcriptText
  .replace(/\[MUSIC\]/g, '')
  .replace(/\[INAUDIBLE\]/g, '[unclear]')
  .trim();

// Split into segments if available
const segments = transcription.segments || [];

// Get meeting metadata from upstream
const config = $('Validate Config & Build Params').item.json.config;
const metadata = $('Validate Config & Build Params').item.json.metadata;

// Calculate duration
const duration = segments.length > 0 
  ? segments[segments.length - 1].end 
  : null;

// Count words and speakers
const wordCount = transcriptText.split(/\s+/).length;
const speakerCount = new Set(
  segments.filter(s => s.speaker).map(s => s.speaker)
).size;

return {
  json: {
    transcript: {
      fullText: transcriptText,
      segments,
      wordCount,
      speakerCount,
      durationSeconds: duration,
      language: config.transcriptionLanguage
    },
    meeting: {
      title: config.meetingTitle,
      date: config.meetingDate,
      attendees: config.attendees,
      projectKey: config.projectKey
    },
    config,
    metadata
  }
};

// Parse Claude's response
const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

// Handle content array format
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

// Clean JSON from markdown
const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let analysis;
try {
  analysis = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Failed to parse AI analysis: ${error.message}`);
}

// Get upstream data
const config = $('Validate Config & Build Params').item.json.config;
const teamMapping = $('Validate Config & Build Params').item.json.teamMapping;
const metadata = $('Validate Config & Build Params').item.json.metadata;
const transcript = $('Parse & Clean Transcript').item.json.transcript;
const meeting = $('Parse & Clean Transcript').item.json.meeting;

// Match assignees to team member IDs
const actionItemsWithIds = (analysis.actionItems || []).map((item, index) => {
  let assigneeData = null;

  if (item.assignee) {
    // Try to match by email or name
    const assigneeLower = item.assignee.toLowerCase();

    for (const [email, userData] of Object.entries(teamMapping)) {
      if (
        email.toLowerCase() === assigneeLower ||
        userData.name.toLowerCase().includes(assigneeLower) ||
        assigneeLower.includes(userData.name.toLowerCase().split(' ')[0])
      ) {
        assigneeData = {
          email,
          ...userData
        };
        break;
      }
    }
  }

  return {
    ...item,
    id: `${metadata.workflowId}-task-${index + 1}`,
    assigneeData,
    createdFrom: 'meeting-automator'
  };
});

return {
  json: {
    analysis: {
      ...analysis,
      actionItems: actionItemsWithIds
    },
    meeting,
    transcript,
    config,
    teamMapping,
    metadata,
    stats: {
      totalActionItems: actionItemsWithIds.length,
      assignedItems: actionItemsWithIds.filter(i => i.assigneeData).length,
      unassignedItems: actionItemsWithIds.filter(i => !i.assigneeData).length,
      decisionsCount: (analysis.decisions || []).length,
      risksCount: (analysis.risks || []).length,
      highPriorityItems: actionItemsWithIds.filter(i => i.priority === 'high').length
    }
  }
};

