// Build comprehensive meeting summary document
const data = $input.item.json;
const analysis = data.analysis;
const meeting = data.meeting;
const stats = data.stats;

const markdown = `# ${meeting.title}
**Date:** ${meeting.date}
**Attendees:** ${meeting.attendees.join(', ')}
**Duration:** ${Math.floor(data.transcript.durationSeconds / 60)} minutes

---

## Executive Summary
${analysis.meetingSummary}

## Statistics
- Total Action Items: ${stats.totalActionItems}
- High Priority Items: ${stats.highPriorityItems}
- Decisions Made: ${stats.decisionsCount}
- Risks Identified: ${stats.risksCount}

---

## Action Items (${stats.totalActionItems})

${analysis.actionItems.map((item, i) => `
### ${i + 1}. ${item.title}
- **Assignee:** ${item.assigneeData?.name || item.assignee || 'Unassigned'}
- **Priority:** ${item.priority.toUpperCase()}
- **Due Date:** ${item.dueDate || 'Not specified'}
- **Labels:** ${item.labels?.join(', ') || 'None'}
- **Estimated Hours:** ${item.estimatedHours || 'TBD'}

${item.description}

**Context:** ${item.context || 'N/A'}
`).join('\n')}

---

## Decisions Made (${stats.decisionsCount})

${(analysis.decisions || []).map((dec, i) => `
${i + 1}. **${dec.decision}**
   - Decision Maker: ${dec.decisionMaker}
   - Impact: ${dec.impact.toUpperCase()}
   - Rationale: ${dec.rationale}
`).join('\n')}

---

## Risks & Blockers (${stats.risksCount})

${(analysis.risks || []).map((risk, i) => `
${i + 1}. **${risk.risk}**
   - Severity: ${risk.severity.toUpperCase()}
   - Mentioned By: ${risk.mentionedBy}
   - Mitigation: ${risk.mitigation || 'TBD'}
`).join('\n')}

---

## Key Discussion Points

${(analysis.discussionPoints || []).map((point, i) => `
### ${point.topic}
${point.summary}
*Time spent: ${point.timeSpent}*
`).join('\n')}

---

## Next Steps

${(analysis.nextSteps || []).map((step, i) => `
${i + 1}. ${step.description}
   - Owner: ${step.owner}
   - Tentative Date: ${step.tentativeDate || 'TBD'}
`).join('\n')}

---

## Full Transcript

${data.transcript.fullText}

---

*Generated by Meeting Notes Automator*
*Workflow ID: ${data.metadata.workflowId}*
*Generated at: ${new Date().toISOString()}*
`;

return {
  json: {
    ...data,
    summaryDocument: markdown
  },
  binary: {
    data: {
      data: Buffer.from(markdown).toString('base64'),
      mimeType: 'text/markdown',
      fileName: `${meeting.title} - Meeting Notes - ${meeting.date}.md`
    }
  }
};

// Build final response with all task links and summary
const allData = $input.all();
const mainData = allData[0].json;
const createdTasks = allData.slice(1).map(item => item.json);

const response = {
  success: true,
  message: `Successfully processed meeting and created ${mainData.stats.totalActionItems} action items`,
  meeting: {
    title: mainData.meeting.title,
    date: mainData.meeting.date,
    attendees: mainData.meeting.attendees,
    duration: `${Math.floor(mainData.transcript.durationSeconds / 60)} minutes`,
    wordCount: mainData.transcript.wordCount
  },
  summary: {
    executiveSummary: mainData.analysis.meetingSummary,
    totalActionItems: mainData.stats.totalActionItems,
    assignedItems: mainData.stats.assignedItems,
    unassignedItems: mainData.stats.unassignedItems,
    highPriorityItems: mainData.stats.highPriorityItems,
    decisionsCount: mainData.stats.decisionsCount,
    risksCount: mainData.stats.risksCount
  },
  actionItems: mainData.analysis.actionItems.map(item => ({
    id: item.id,
    title: item.title,
    assignee: item.assigneeData?.name || item.assignee || 'Unassigned',
    priority: item.priority,
    dueDate: item.dueDate,
    taskUrl: createdTasks.find(t => t.summary === item.title)?.url || '#',
    status: 'created'
  })),
  decisions: mainData.analysis.decisions || [],
  risks: mainData.analysis.risks || [],
  nextSteps: mainData.analysis.nextSteps || [],
  notifications: {
    sent: mainData.config.sendNotifications,
    recipientCount: mainData.stats.assignedItems
  },
  storage: {
    savedToDrive: mainData.config.saveToDrive,
    savedToNotion: mainData.config.saveToNotion,
    summaryUrl: '#' // Would be populated by Drive/Notion response
  },
  metadata: {
    workflowId: mainData.metadata.workflowId,
    processedAt: new Date().toISOString(),
    taskTool: mainData.config.taskTool
  }
};

return [{ json: response }];
